15	static CURRENT_LOCALE: LazyLock<AtomicStr> = LazyLock::new(|| AtomicStr::from("en"));
16	
17	/// Set current locale
18	pub fn set_locale(locale: &str) {
19	    CURRENT_LOCALE.replace(locale);
20	}
