77	            }
78	            return if report_file_lookup_errors {
79	                Err(format!("Path '{locales_path}' cannot be normalized: '{e}'"))
80	            } else {
81	                Ok(result)
82	            };
83	        }
84	    };
85	    let locales_path = match locales_path.as_path().to_str() {
86	        Some(p) => p,
87	        None => {
88	            if is_debug() {
89	                println!("cargo:i18n-error=could not convert path");
90	            }
91	            return if report_file_lookup_errors {
92	                Err("Could not convert path.".to_string())
93	            } else {
94	                Ok(result)
95	            };
96	        }
97	    };
98	
99	    let path_pattern = format!("{locales_path}/**/*.{{yml,yaml,json,toml}}");
100	
101	    if is_debug() {
102	        println!("cargo:i18n-locale={}", &path_pattern);
103	    }
104	
105	    // check dir exists
106	    if !Path::new(locales_path).exists() {
107	        if is_debug() {
108	            println!("cargo:i18n-error=path not exists: {}", locales_path);
109	        }
110	        return if report_file_lookup_errors {
111	            Err(format!("Path '{locales_path}' not found."))
112	        } else {
113	            Ok(result)
114	        };
115	    }
116	
117	    for entry in globwalk::glob(&path_pattern)
118	        .map_err(|error| format!("Failed to read glob pattern: {error}"))?
119	    {
120	        let entry = entry.unwrap().into_path();
121	        if is_debug() {
122	            println!("cargo:i18n-load={}", &entry.display());
123	        }
124	
125	        if ignore_if(&entry.display().to_string()) {
126	            continue;
127	        }
128	
129	        let locale = entry
130	            .file_stem()
131	            .and_then(|s| s.to_str())
132	            .and_then(|s| s.split('.').last())
133	            .unwrap();
134	
135	        let ext = entry.extension().and_then(|s| s.to_str()).unwrap();
136	
137	        let file = File::open(&entry)
138	            .map_err(|error| format!("Failed to open file '{entry:?}': {error}"))?;
139	        let mut reader = std::io::BufReader::new(file);
140	        let mut content = String::new();
141	
142	        reader
143	            .read_to_string(&mut content)
144	            .map_err(|error| format!("Read file '{entry:?}' failed: {error}."))?;
145	
146	        let trs = parse_file(&content, ext, locale).map_err(|error| {
147	            format!("Parse file `{}` failed, reason: {}", entry.display(), error)
148	        })?;
149	
150	        trs.into_iter().for_each(|(k, new_value)| {
151	            translations
152	                .entry(k)
153	                .and_modify(|old_value| merge_value(old_value, &new_value))
154	                .or_insert(new_value);
155	        });
156	    }
157	
158	    translations.iter().for_each(|(locale, trs)| {
159	        result.insert(locale.to_string(), flatten_keys("", trs));
160	    });
161	
162	    Ok(result)
163	}
