342	    fn filter_arguments(&mut self) -> syn::parse::Result<()> {
343	        for arg in self.args.iter() {
344	            match arg.name.as_str() {
345	                "locale" => {
346	                    self.locale = Some(arg.value.clone());
347	                }
348	                "_minify_key" => {
