153	#[cfg(test)]
154	mod tests {
155	    use super::*;
156	    use std::str::FromStr;
157	
158	    macro_rules! build_messages {
159	        {$(($key:tt, $($line:tt),+)),+} => {{
160	            let mut results = Vec::<Message>::new();
161	            $(
162	                let message = Message {
163	                    key: $key.into(),
164	                    locations: vec![
165	                        $(
166	                            Location {
167	                                file: PathBuf::from_str("hello.rs").unwrap(),
168	                                line: $line
169	                            },
170	                        )+
171	                    ],
172	                    index: 0,
173	                    minify_key: false,
174	                };
175	                results.push(message);
176	            )+
177	
178	            results
179	        }}
180	    }
