8	type Translations = HashMap<String, HashMap<String, String>>;
9	
10	pub fn generate<'a, P: AsRef<Path>>(
11	    output_path: P,
12	    all_locales: &Vec<String>,
13	    messages: impl IntoIterator<Item = (&'a String, &'a Message)> + Clone,
14	) -> Result<()> {
15	    let filename = "TODO.yml";
16	    let format = "yaml";
17	
18	    let trs = generate_result(&output_path, filename, all_locales, messages);
19	
20	    if trs.is_empty() {
21	        println!("All thing done.\n");
22	
23	        return Ok(());
24	    }
25	
26	    eprintln!("Found {} new texts need to translate.", trs.len());
27	    eprintln!("----------------------------------------");
28	    eprintln!("Writing to {}\n", filename);
29	
30	    let text = convert_text(&trs, format);
31	    write_file(&output_path, filename, &text)?;
32	
33	    // Finally, return error for let CI fail
34	    let err = std::io::Error::new(std::io::ErrorKind::Other, "");
35	    Err(err)
36	}
37	
38	fn convert_text(trs: &Translations, format: &str) -> String {
39	    let mut value = serde_json::Value::Object(serde_json::Map::new());
40	    value["_version"] = serde_json::Value::Number(serde_json::Number::from(2));
41	
42	    for (key, val) in trs {
43	        let mut obj = serde_json::Value::Object(serde_json::Map::new());
44	        for (locale, text) in val {
45	            obj[locale] = serde_json::Value::String(text.clone());
46	        }
47	        value[key] = obj;
48	    }
49	
50	    match format {
51	        "json" => serde_json::to_string_pretty(&value).unwrap(),
52	        "yaml" | "yml" => {
53	            let text = serde_yaml::to_string(&value).unwrap();
54	            // Remove leading `---`
55	            text.trim_start_matches("---").trim_start().to_string()
56	        }
57	        "toml" => toml::to_string_pretty(&value).unwrap(),
58	        _ => unreachable!(),
59	    }
60	}
61	
62	fn generate_result<'a, P: AsRef<Path>>(
63	    output_path: P,
64	    output_filename: &str,
65	    all_locales: &Vec<String>,
66	    messages: impl IntoIterator<Item = (&'a String, &'a Message)> + Clone,
67	) -> Translations {
68	    let mut trs = Translations::new();
69	
70	    for locale in all_locales {
71	        println!("Checking [{}] and generating untranslated texts...", locale);
72	
73	        // ~/work/my-project/locales
74	        let output_path = output_path.as_ref().display().to_string();
75	
76	        let ignore_file = |fname: &str| fname.ends_with(&output_filename);
77	        let data = load_locales(&output_path, ignore_file);
78	
79	        for (key, m) in messages.clone() {
80	            if !m.locations.is_empty() {
81	                for _l in &m.locations {
82	                    // TODO: write file and line as YAML comment
83	                    // Reason: serde_yaml not support write comments
84	                    // https://github.com/dtolnay/serde-yaml/issues/145
85	                }
86	            }
87	
88	            if let Some(trs) = data.get(locale) {
89	                if trs.get(key).is_some() {
90	                    continue;
91	                }
92	            }
93	
94	            let value = if m.minify_key {
95	                m.key.to_owned()
96	            } else {
97	                m.key.split('.').last().unwrap_or_default().to_string()
98	            };
99	
100	            trs.entry(key.clone())
101	                .or_default()
102	                .insert(locale.to_string(), value.to_string());
103	        }
104	    }
105	
106	    trs
107	}
108	
109	fn write_file<P: AsRef<Path>>(output: &P, filename: &str, data: &str) -> Result<()> {
110	    let output_file = std::path::Path::new(output.as_ref()).join(String::from(filename));
111	    let folder = output_file.parent().unwrap();
112	
113	    // Ensure create folder
114	    if !folder.exists() {
115	        std::fs::create_dir_all(folder).unwrap();
116	    }
